<?php declare(strict_types=1);
namespace SkyFi\System\Controllers;
use SkyFi\Shared\Http\{ApiResponse,Request,Response};
use SkyFi\System\Services\SystemAdministrationService;
final class SystemSettingsController extends SystemBaseController { public function __construct(private readonly SystemAdministrationService $service, \SkyFi\Rbac\Middleware\RequirePermissionMiddleware $p){parent::__construct($p);} public function show(Request $r): Response { $this->user($r,'system.view'); $d=$this->service->settings->first(); return ApiResponse::resource('system-settings',(string)$d['id'],$d); } public function update(Request $r): Response { $u=$this->user($r,'system.update'); $d=$this->service->updateSettings($r->body(),$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::resource('system-settings',(string)$d['id'],$d); } public function enableMaintenance(Request $r): Response { $u=$this->user($r,'system.manage'); $d=$this->service->updateSettings(['maintenance_mode'=>1,'maintenance_message'=>$r->body()['maintenance_message']??'Maintenance mode is enabled.'],$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::resource('system-settings',(string)$d['id'],$d); } public function disableMaintenance(Request $r): Response { $u=$this->user($r,'system.manage'); $d=$this->service->updateSettings(['maintenance_mode'=>0],$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::resource('system-settings',(string)$d['id'],$d); }}
